// ─── ASSEMBLE ALL 800 QUESTIONS ───
export function generateAllCamrtQuestions(): CamrtQuestion[] {
  const all: CamrtQuestion[] = [];
  all.push(...patientCareQuestions());       // ~40 questions
  all.push(...radiationProtectionQuestions()); // ~35 questions
  all.push(...imageProductionQuestions());    // ~35 questions
  all.push(...imageEvaluationQuestions());    // ~25 questions
  all.push(...radiographicProceduresQuestions()); // ~40 questions
  all.push(...supplementaryQuestions());       // ~40 questions

  // Generate additional questions to reach 800 using domain-balanced templates
  const domains = ["Patient Care", "Radiation Protection", "Image Production", "Image Evaluation", "Radiographic Procedures"];
  const difficultyLevels = [1, 2, 2, 2, 3, 3, 4]; // weighted toward medium

  // We have ~215 hand-crafted questions. Generate remaining ~585 using templated variations.
  const templates = generateTemplatedQuestions();
  all.push(...templates);

  return all.slice(0, 800);
}

