// ─── 30 ARTIFACT RECOGNITION ENTRIES ───
export function generateCamrtArtifactEntries(): CamrtArtifactEntry[] {
  return [
    { front: "Motion Artifact", back: "Cause: Patient moved during exposure (voluntary or involuntary). Appearance: Blurred anatomical structures. Correction: Use shorter exposure time, immobilize patient, clear breathing instructions, use higher mA.", category: "Motion", difficulty: 1 },
    { front: "Grid Cutoff — Off-Level", back: "Cause: Grid tilted (not perpendicular to CR). Appearance: Overall density loss across entire image. Correction: Level the grid perpendicular to the central ray.", category: "Grid", difficulty: 2 },
    { front: "Grid Cutoff — Off-Center (Lateral Decentering)", back: "Cause: Central ray not aligned with the center of the grid. Appearance: Density loss on one side of the image. Correction: Center the tube to the grid center line.", category: "Grid", difficulty: 2 },
    { front: "Grid Cutoff — Off-Focus (Wrong SID)", back: "Cause: SID outside the grid's focal range. Appearance: Density loss on both sides of the image (center acceptable). Correction: Use the grid within its specified focal range.", category: "Grid", difficulty: 3 },
    { front: "Upside-Down Focused Grid", back: "Cause: Focused grid placed with the wrong side facing the tube. Appearance: Acceptable density in center, severe cutoff (whiteness) on both sides. Correction: Verify grid orientation before exposure.", category: "Grid", difficulty: 2 },
    { front: "Quantum Mottle (Noise)", back: "Cause: Insufficient photons reaching the detector (underexposure / low mAs). Appearance: Grainy, mottled, salt-and-pepper texture, especially in uniform areas. Correction: Increase mAs. Check exposure indicator.", category: "Noise", difficulty: 2 },
    { front: "Overexposure (Saturation)", back: "Cause: Excessive mAs or kVp resulting in too many photons reaching the detector. Appearance: In digital — may look acceptable but EI is elevated; in film — overall darkness. Correction: Reduce mAs or kVp. Monitor exposure indicators.", category: "Exposure", difficulty: 1 },
    { front: "Underexposure", back: "Cause: Insufficient mAs or kVp. Appearance: In digital — increased noise, poor SNR; in film — overall lightness. Correction: Increase mAs or kVp. Check AEC selection.", category: "Exposure", difficulty: 1 },
    { front: "Double Exposure", back: "Cause: CR plate not erased before reuse, or DR detector exposed twice without readout. Appearance: Two superimposed images (ghosting). Correction: Always erase CR plates. Ensure DR readout between exposures.", category: "Processing", difficulty: 2 },
    { front: "Moiré Pattern (Zebra Artifact)", back: "Cause: Stationary grid line frequency interfering with DR detector pixel frequency. Appearance: Repetitive zebra-stripe or wavy pattern. Correction: Use reciprocating (moving) grid, or adjust grid frequency, or remove grid.", category: "Grid", difficulty: 3 },
    { front: "Static Discharge Artifact", back: "Cause: Static electricity discharge on CR imaging plate (low humidity). Appearance: Branching, tree-like, or lightning-bolt patterns. Correction: Control humidity, handle plates carefully, use anti-static measures.", category: "Handling", difficulty: 2 },
    { front: "Crescent/Half-Moon Artifact", back: "Cause: Bending, rough handling, or mechanical stress on CR imaging plate. Appearance: Crescent or half-moon shaped marks. Correction: Handle plates gently, avoid bending, replace damaged plates.", category: "Handling", difficulty: 2 },
    { front: "Foreign Object Artifact", back: "Cause: Radiopaque objects in imaging field (jewelry, snaps, buttons, hair accessories). Appearance: Bright white objects superimposed on anatomy. Correction: Remove all radiopaque objects before imaging.", category: "Foreign Body", difficulty: 1 },
    { front: "Rotation Artifact (Positioning Error)", back: "Cause: Patient rotated from true AP/PA/lateral position. Appearance: Asymmetric anatomy (e.g., unequal clavicle-spinous process distances on chest). Correction: Ensure proper patient positioning with landmarks.", category: "Positioning", difficulty: 1 },
    { front: "Poor Collimation", back: "Cause: Insufficient collimation allowing excessive primary beam area. Appearance: Unnecessary anatomy exposed, increased scatter, potential histogram error. Correction: Collimate to area of interest. Follow ALARA.", category: "Technique", difficulty: 1 },
    { front: "Clipped Anatomy", back: "Cause: Anatomy of interest partially cut off due to improper centering, small cassette, or tight collimation. Appearance: Missing anatomy at edges. Correction: Verify centering, use appropriate IR size, include all required anatomy.", category: "Positioning", difficulty: 1 },
    { front: "Histogram Analysis Error", back: "Cause: Incorrect body part algorithm selection, excessive unattenuated radiation at field edges, or atypical patient anatomy (prostheses). Appearance: Inappropriate image processing — too dark, too light, or wrong contrast. Correction: Select correct algorithm, improve collimation, manually adjust.", category: "Processing", difficulty: 3 },
    { front: "Beam Hardening Artifact (CT)", back: "Cause: Preferential absorption of low-energy photons by dense structures (bone, metal). Appearance: Dark bands/streaks between dense structures (e.g., petrous bones on brain CT). Correction: Use beam hardening correction algorithms, increase kVp.", category: "CT", difficulty: 3 },
    { front: "Ring Artifact (CT)", back: "Cause: Miscalibrated or defective detector element in the CT detector array. Appearance: Concentric ring patterns centered on the rotation axis. Correction: Detector calibration, replace defective detector element.", category: "CT", difficulty: 3 },
    { front: "Stair-Step Artifact (CT)", back: "Cause: Thick slices or high pitch in helical CT when reformatting in planes other than axial. Appearance: Jagged, stair-step edges on reformatted images. Correction: Use thinner slices, reduce pitch, apply smoothing algorithm.", category: "CT", difficulty: 2 },
    { front: "Partial Volume Artifact (CT)", back: "Cause: A voxel contains tissues of different densities, averaged into one HU value. Appearance: Blurring of edges, pseudolesions, or incorrect density measurements. Correction: Use thinner slices to reduce partial volume effect.", category: "CT", difficulty: 2 },
    { front: "Metal Streak Artifact (CT)", back: "Cause: High-density metallic objects (implants, dental fillings) cause photon starvation and beam hardening. Appearance: Bright and dark streaks radiating from metal. Correction: Use MAR algorithms, increase kVp, dual-energy CT.", category: "CT", difficulty: 2 },
    { front: "Patient Motion Artifact (CT)", back: "Cause: Patient movement during CT acquisition. Appearance: Blurring, doubling of structures, streak artifacts. Correction: Coach patient, use faster scan times, immobilize, prospective gating for cardiac CT.", category: "CT", difficulty: 1 },
    { front: "Mach Effect (Not a True Artifact)", back: "Cause: Optical illusion by the human visual system at interfaces of differing densities. Appearance: Apparent dark or light band at tissue borders. Can mimic pneumothorax. Not a real anatomical finding. Recognition: Evaluate clinically; may need repeat or different modality.", category: "Optical", difficulty: 3 },
    { front: "Backscatter Artifact", back: "Cause: Radiation scattered from the table or cassette tray back to the imaging plate. Appearance: Ghost images of table components or lead letters on the wrong side. Correction: Place lead backing behind CR cassette.", category: "Technique", difficulty: 2 },
    { front: "Image Plate Reader Artifact (CR)", back: "Cause: Dirty laser optics, worn rollers, or contamination in the CR reader. Appearance: Lines, bands, or streaks in the direction of plate travel. Correction: Clean reader components, maintain regularly.", category: "Equipment", difficulty: 2 },
    { front: "Incorrect Marker Placement", back: "Cause: Lead anatomical marker (R/L) placed outside collimated field or not placed before exposure. Appearance: Missing or illegible R/L marker, requiring digital annotation or repeat. Correction: Always place marker within field before exposure.", category: "Technique", difficulty: 1 },
    { front: "Grid Lines Visible", back: "Cause: Stationary grid used without adequate focal spot-grid alignment, or grid frequency too low for digital detector. Appearance: Visible grid lines across the image. Correction: Use reciprocating grid, higher frequency grid, or increase SID.", category: "Grid", difficulty: 2 },
    { front: "Fog (General)", back: "Cause: Scatter radiation, light leaks, chemical contamination (film), or improper processing. Appearance: Overall gray haze reducing contrast. Correction: Use grid, collimate, check processing, check for light leaks.", category: "Technique", difficulty: 1 },
    { front: "Aliasing Artifact (Digital)", back: "Cause: Sampling frequency below the Nyquist frequency for the spatial frequencies present. Appearance: Fine structures appear distorted or show false patterns. Correction: Use higher resolution detector, apply anti-aliasing filters.", category: "Digital", difficulty: 3 },
  ];
}

// ─── 15 CASE STUDIES ───
export function generateCamrtCaseStudies(): CamrtCaseStudy[] {
  return [
    { title: "Pneumothorax Detection on Chest Radiography", clinicalHistory: "23-year-old male presents to the emergency department with sudden onset right-sided chest pain and shortness of breath after playing basketball. No history of trauma. Vital signs: HR 110, BP 118/72, RR 24, SpO2 93%.", findings: [{ finding: "Visceral pleural line visible on the right", description: "Thin white line parallel to the chest wall with absent lung markings peripherally" }, { finding: "Absent lung markings", description: "No pulmonary vessels visible lateral to the pleural line" }, { finding: "Deep sulcus sign", description: "Unusually deep right costophrenic angle suggesting air tracking inferiorly" }], diagnosis: "Right-sided spontaneous pneumothorax (approximately 30%)", discussionPoints: [{ point: "Positioning considerations", detail: "Erect PA chest with expiration film may accentuate a small pneumothorax" }, { point: "Technical factors", detail: "Ensure adequate exposure to visualize the thin pleural line. Digital post-processing may help" }, { point: "Additional views", detail: "Lateral decubitus with affected side UP may demonstrate small pneumothorax not visible on PA" }], imageRefs: ["pneumothorax-pa-chest.jpg", "deep-sulcus-sign.jpg"], difficulty: "medium", questions: [{ q: "Which position best demonstrates a small pneumothorax?", opts: ["PA inspiration", "PA expiration", "Supine AP", "Lateral decubitus, affected side down"], correct: 1, rationale: "PA expiration decreases lung volume, making the pneumothorax relatively larger and more visible. The lung moves away from the chest wall more during expiration." }, { q: "What is the deep sulcus sign?", opts: ["Elevated hemidiaphragm", "Unusually deep costophrenic angle from air tracking inferiorly", "Fluid layering", "Rib fracture"], correct: 1, rationale: "The deep sulcus sign is an unusually deep, lucent costophrenic angle seen on supine or semi-erect radiographs when air collects at the base of the pleural space." }] },
    { title: "Scaphoid Fracture Evaluation", clinicalHistory: "28-year-old female fell on an outstretched hand (FOOSH) while snowboarding. Complaining of pain in the anatomical snuffbox of the right wrist. Initial PA and lateral wrist radiographs appear normal.", findings: [{ finding: "Normal initial radiographs", description: "No visible fracture on standard PA and lateral views" }, { finding: "Clinical suspicion high", description: "Anatomical snuffbox tenderness is highly specific for scaphoid fracture" }], diagnosis: "Suspected occult scaphoid fracture", discussionPoints: [{ point: "Dedicated scaphoid views", detail: "PA with ulnar deviation elongates the scaphoid and may reveal the fracture" }, { point: "Follow-up imaging", detail: "If initial films are negative, immobilize and repeat in 10-14 days, or obtain MRI/CT" }, { point: "Complications", detail: "Scaphoid has retrograde blood supply — fractures can lead to avascular necrosis if untreated" }], imageRefs: ["scaphoid-ulnar-deviation.jpg", "scaphoid-fracture-followup.jpg"], difficulty: "medium", questions: [{ q: "Which projection best demonstrates the scaphoid?", opts: ["PA with radial deviation", "PA with ulnar deviation", "Lateral wrist", "Carpal tunnel view"], correct: 1, rationale: "PA with ulnar deviation elongates the scaphoid and opens the scaphoid fat stripe, making fractures more visible." }, { q: "Why is the scaphoid fracture clinically significant?", opts: ["It is the most common bone fracture", "The scaphoid has a retrograde blood supply; fractures can cause avascular necrosis", "It always requires surgery", "It heals quickly"], correct: 1, rationale: "The scaphoid's blood supply enters distally, so fractures (especially at the waist or proximal pole) can disrupt blood flow, leading to avascular necrosis." }] },
    { title: "Pediatric Elbow Fracture — Fat Pad Sign", clinicalHistory: "7-year-old boy fell off a playground structure onto his outstretched right arm. Complaining of elbow pain and refusing to move the arm. No visible deformity.", findings: [{ finding: "Anterior fat pad elevated (sail sign)", description: "The anterior fat pad is displaced anteriorly and upward, forming a 'sail' shape" }, { finding: "Posterior fat pad visible", description: "The posterior fat pad is visible (normally hidden in the olecranon fossa)" }, { finding: "No obvious fracture line visible", description: "Bony structures appear intact on AP and lateral views" }], diagnosis: "Occult elbow fracture (most likely supracondylar fracture) indicated by positive fat pad sign", discussionPoints: [{ point: "Fat pad significance", detail: "Visible posterior fat pad = joint effusion = presumed fracture until proven otherwise in trauma" }, { point: "Most common pediatric elbow fracture", detail: "Supracondylar fracture (60% of pediatric elbow fractures)" }, { point: "Positioning", detail: "True lateral with 90° flexion essential for fat pad evaluation" }], imageRefs: ["elbow-fat-pad-sail-sign.jpg", "pediatric-supracondylar-fracture.jpg"], difficulty: "medium", questions: [{ q: "What does a visible posterior fat pad on lateral elbow indicate?", opts: ["Normal finding", "Joint effusion, presumed fracture in trauma", "Tendon injury", "Equipment artifact"], correct: 1, rationale: "The posterior fat pad is normally hidden in the olecranon fossa. When visible on a lateral elbow radiograph, it indicates joint effusion. In the setting of trauma, this is presumed to be a hemarthrosis from an occult fracture." }, { q: "What is the most common pediatric elbow fracture?", opts: ["Radial head fracture", "Olecranon fracture", "Supracondylar fracture", "Coronoid fracture"], correct: 2, rationale: "Supracondylar fractures account for approximately 60% of pediatric elbow fractures, typically from a fall on an outstretched hand." }] },
    { title: "Small Bowel Obstruction on Abdominal Radiograph", clinicalHistory: "65-year-old female with a history of prior abdominal surgery presents with abdominal distention, nausea, vomiting, and inability to pass flatus for 24 hours.", findings: [{ finding: "Dilated small bowel loops", description: "Multiple dilated loops >3 cm with visible valvulae conniventes (plicae circulares)" }, { finding: "Air-fluid levels on upright", description: "Multiple differential air-fluid levels at varying heights" }, { finding: "Absent colonic gas", description: "No gas in the colon or rectum suggesting complete obstruction" }], diagnosis: "Small bowel obstruction (likely adhesive from prior surgery)", discussionPoints: [{ point: "Three-view abdomen", detail: "Supine AP, upright AP (or left lateral decubitus), and upright chest for free air" }, { point: "Key differentiators", detail: "Small bowel: central, valvulae conniventes, <5 cm normal. Large bowel: peripheral, haustra, <8 cm normal" }, { point: "Technical considerations", detail: "Adequate exposure to see bowel gas pattern. Include symphysis to diaphragm" }], imageRefs: ["sbo-supine-abdomen.jpg", "sbo-upright-air-fluid-levels.jpg"], difficulty: "hard", questions: [{ q: "What is the normal maximum diameter of small bowel?", opts: ["2 cm", "3 cm", "5 cm", "8 cm"], correct: 1, rationale: "Normal small bowel should not exceed 3 cm in diameter. The rule of 3-6-9: small bowel >3 cm, large bowel >6 cm, and cecum >9 cm are considered dilated." }, { q: "What finding best distinguishes small bowel from large bowel on radiograph?", opts: ["Location only", "Valvulae conniventes (small) vs haustra (large)", "Size only", "Gas content"], correct: 1, rationale: "Valvulae conniventes (plicae circulares) extend completely across the lumen in small bowel. Haustra in large bowel only partially cross the lumen. Location (central vs peripheral) also helps." }] },
    { title: "Shoulder Dislocation Assessment", clinicalHistory: "45-year-old male presents after a fall while skiing. Left shoulder is painful, externally rotated, and squared off in appearance. Unable to move the arm.", findings: [{ finding: "Humeral head inferior and medial to glenoid", description: "On AP view, the humeral head is displaced below the glenoid fossa" }, { finding: "Light bulb sign", description: "The humeral head appears round like a light bulb due to internal rotation (locked)" }, { finding: "Hill-Sachs deformity", description: "Compression fracture of the posterolateral humeral head from impaction against the glenoid rim" }], diagnosis: "Anterior shoulder dislocation with Hill-Sachs deformity", discussionPoints: [{ point: "Standard views", detail: "AP shoulder and scapular Y-view (or axillary view if tolerated) to confirm direction" }, { point: "Y-view interpretation", detail: "In anterior dislocation, humeral head is anterior to the Y center. Posterior = posterior dislocation" }, { point: "Associated injuries", detail: "Bankart lesion (anterior glenoid rim fracture), Hill-Sachs lesion, rotator cuff tears, axillary nerve injury" }], imageRefs: ["anterior-shoulder-dislocation-ap.jpg", "shoulder-y-view-dislocation.jpg", "hill-sachs-lesion.jpg"], difficulty: "medium", questions: [{ q: "On a scapular Y-view, where is the humeral head in an anterior dislocation?", opts: ["Centered in the Y", "Anterior to the Y center", "Posterior to the Y center", "Superior to the Y"], correct: 1, rationale: "In anterior dislocation (95% of shoulder dislocations), the humeral head is displaced anterior to the center of the Y on the scapular Y-view." }, { q: "What is a Hill-Sachs lesion?", opts: ["Fracture of the glenoid rim", "Compression fracture of the posterolateral humeral head", "Rotator cuff tear", "Labral tear"], correct: 1, rationale: "A Hill-Sachs lesion is a compression fracture of the posterolateral humeral head caused by impaction against the anterior glenoid rim during anterior dislocation." }] },
    { title: "Cervical Spine Trauma — Lateral View", clinicalHistory: "35-year-old male involved in a motor vehicle collision. Cervical collar in place. Complaining of neck pain. GCS 15.", findings: [{ finding: "C5-C6 subluxation", description: "Anterior displacement of C5 on C6 with widening of the interspinous space" }, { finding: "Prevertebral soft tissue swelling", description: "Prevertebral soft tissue width >7 mm at C2 level and >22 mm at C6 level" }, { finding: "Loss of normal lordotic curve", description: "Straightening or reversal of the normal cervical lordosis" }], diagnosis: "Bilateral facet dislocation at C5-C6 (unstable injury)", discussionPoints: [{ point: "Critical evaluation points", detail: "Four lines on lateral C-spine: anterior vertebral body line, posterior vertebral body line, spinolaminar line, and spinous process tips" }, { point: "Soft tissue", detail: "Prevertebral soft tissue swelling suggests hemorrhage/edema from injury. Normal: <7mm at C2, <22mm at C6" }, { point: "Technical requirements", detail: "Must visualize C1-T1. If C7-T1 not seen, swimmer's lateral or CT required" }], imageRefs: ["c-spine-subluxation-lateral.jpg", "prevertebral-swelling.jpg"], difficulty: "hard", questions: [{ q: "What is the normal prevertebral soft tissue width at the C2 level?", opts: ["<3 mm", "<7 mm", "<14 mm", "<22 mm"], correct: 1, rationale: "Normal prevertebral soft tissue width at C2 (retropharyngeal space) should be <7 mm. At C6 (retrotracheal space), it should be <22 mm. Widening suggests hemorrhage or edema from injury." }, { q: "How many vertebrae must be demonstrated on a lateral cervical spine?", opts: ["5 (C1-C5)", "6 (C1-C6)", "7 (C1-C7, including C7-T1 junction)", "Only C1-C2"], correct: 2, rationale: "All 7 cervical vertebrae must be demonstrated, including the C7-T1 junction. If not visualized, a swimmer's lateral or CT is required as pathology at the cervicothoracic junction may be missed." }] },
    { title: "Congestive Heart Failure on Chest Radiograph", clinicalHistory: "72-year-old female with known heart failure presents with worsening dyspnea, orthopnea, and bilateral lower extremity edema over 3 days.", findings: [{ finding: "Cardiomegaly", description: "Cardiothoracic ratio >0.50 on PA chest" }, { finding: "Upper lobe pulmonary venous distension (cephalization)", description: "Upper lobe vessels larger than lower lobe vessels" }, { finding: "Bilateral pleural effusions", description: "Blunting of both costophrenic angles" }, { finding: "Kerley B lines", description: "Short horizontal lines at the lung periphery representing thickened interlobular septa" }], diagnosis: "Acute exacerbation of congestive heart failure", discussionPoints: [{ point: "PA vs AP projection", detail: "Heart size must be evaluated on PA chest at 180 cm SID. AP magnifies the heart and can mimic cardiomegaly" }, { point: "Cardiothoracic ratio", detail: "Maximum cardiac width / maximum thoracic width. >0.50 on PA = cardiomegaly" }, { point: "Progression of findings", detail: "Mild: cephalization → Moderate: interstitial edema → Severe: alveolar edema (bat-wing pattern)" }], imageRefs: ["chf-cardiomegaly-pa.jpg", "chf-cephalization.jpg", "kerley-b-lines.jpg"], difficulty: "medium", questions: [{ q: "What is the normal cardiothoracic ratio on a PA chest?", opts: ["<0.30", "<0.40", "<0.50", "<0.60"], correct: 2, rationale: "The normal cardiothoracic ratio is <0.50 (50%) on a PA chest radiograph at 180 cm SID. Ratios >0.50 indicate cardiomegaly." }, { q: "Why must heart size be assessed on PA rather than AP?", opts: ["PA uses lower kVp", "AP magnifies the heart because it is farther from the image receptor", "PA is faster", "AP uses more radiation"], correct: 1, rationale: "In AP projection, the heart is farther from the image receptor, causing 15-20% magnification. This can falsely suggest cardiomegaly. PA projection minimizes cardiac magnification." }] },
    { title: "Scoliosis Assessment with Full-Spine Imaging", clinicalHistory: "14-year-old female referred by pediatrician for follow-up of known adolescent idiopathic scoliosis. Previous Cobb angle was 22 degrees.", findings: [{ finding: "Right thoracic curvature", description: "Convexity to the right in the thoracic region, measured T5-T12" }, { finding: "Compensatory left lumbar curve", description: "Compensatory curvature in the lumbar region" }], diagnosis: "Progressive adolescent idiopathic scoliosis — Cobb angle now 28 degrees", discussionPoints: [{ point: "Full-spine imaging", detail: "PA (not AP) to reduce breast dose in adolescent females. Full-spine standing view with image stitching" }, { point: "Cobb angle measurement", detail: "Measured between the most tilted vertebrae (end vertebrae) at the top and bottom of the curve" }, { point: "Dose reduction", detail: "PA projection reduces breast dose by 96%. Use appropriate collimation, gonadal shielding, and breast shields" }], imageRefs: ["scoliosis-full-spine-pa.jpg", "cobb-angle-measurement.jpg"], difficulty: "medium", questions: [{ q: "Why is a PA projection preferred over AP for scoliosis imaging in adolescent females?", opts: ["It provides better image quality", "It reduces breast dose by approximately 96%", "It is faster", "It shows the curve better"], correct: 1, rationale: "PA projection places the breasts on the exit side of the beam, reducing breast dose by approximately 96% compared to AP. This is particularly important for young females who may need repeated imaging." }, { q: "What is the Cobb angle?", opts: ["The angle of tube angulation", "The angle between the most tilted end vertebrae of a spinal curve", "The angle of patient rotation", "The kyphotic angle"], correct: 1, rationale: "The Cobb angle is measured between lines drawn parallel to the superior endplate of the upper end vertebra and the inferior endplate of the lower end vertebra of the scoliotic curve." }] },
    { title: "Ankle Fracture Classification (Weber)", clinicalHistory: "52-year-old female twisted her right ankle stepping off a curb. Ankle is swollen, ecchymotic, and tender over the lateral malleolus.", findings: [{ finding: "Oblique fracture of lateral malleolus at the level of the syndesmosis", description: "Fracture line at the level of the ankle joint on AP and mortise views" }, { finding: "Widening of the medial clear space", description: "Medial clear space >4 mm suggesting deltoid ligament injury" }, { finding: "Intact posterior malleolus", description: "No fracture of the posterior tibial margin" }], diagnosis: "Weber B ankle fracture with deltoid ligament injury (unstable)", discussionPoints: [{ point: "Weber classification", detail: "Type A: below syndesmosis (stable). Type B: at the level (may be unstable). Type C: above syndesmosis (unstable)" }, { point: "Mortise view importance", detail: "15-20° internal rotation opens the ankle mortise to assess medial clear space and talar shift" }, { point: "Three views required", detail: "AP, lateral, and mortise views form the standard ankle series" }], imageRefs: ["weber-b-fracture-mortise.jpg", "widened-medial-clear-space.jpg"], difficulty: "hard", questions: [{ q: "In Weber classification, where is the fracture line in a Type B fibular fracture?", opts: ["Below the syndesmosis", "At the level of the syndesmosis", "Above the syndesmosis", "Through the tibia"], correct: 1, rationale: "Weber B fractures occur at the level of the syndesmosis (ankle joint line). They may or may not disrupt the syndesmotic ligaments. Medial clear space widening suggests instability." }, { q: "What does widening of the medial clear space suggest?", opts: ["Normal finding", "Deltoid ligament injury or medial malleolus fracture", "Lateral ligament injury", "Achilles tendon rupture"], correct: 1, rationale: "A medial clear space >4 mm (or wider than the superior clear space) suggests disruption of the deltoid ligament or a medial malleolus fracture, indicating an unstable ankle injury." }] },
    { title: "Lumbar Spondylolysis and Spondylolisthesis", clinicalHistory: "19-year-old male university athlete (gymnast) presenting with persistent low back pain that worsens with extension activities. Pain radiates to both buttocks.", findings: [{ finding: "Bilateral pars interarticularis defects at L5", description: "'Scotty dog' neck fracture visible on oblique lumbar views" }, { finding: "Anterior displacement of L5 on S1", description: "On lateral view, L5 vertebral body displaced anteriorly relative to S1" }, { finding: "Grade 1 spondylolisthesis", description: "Approximately 15% anterior slippage of L5 on S1" }], diagnosis: "Bilateral L5 spondylolysis with Grade 1 spondylolisthesis", discussionPoints: [{ point: "Oblique views", detail: "45° oblique views demonstrate the 'Scotty dog' appearance. A fracture through the neck (pars) = spondylolysis" }, { point: "Grading", detail: "Meyerding classification: Grade 1 (0-25%), Grade 2 (25-50%), Grade 3 (50-75%), Grade 4 (75-100%), Grade 5 (>100% = spondyloptosis)" }, { point: "Lateral view measurement", detail: "Lateral view best demonstrates the degree of slippage. Measure the percentage of displacement" }], imageRefs: ["scotty-dog-pars-defect.jpg", "spondylolisthesis-lateral.jpg"], difficulty: "hard", questions: [{ q: "What part of the 'Scotty dog' represents the pars interarticularis?", opts: ["Eye", "Ear", "Nose", "Neck"], correct: 3, rationale: "The neck of the Scotty dog represents the pars interarticularis. A fracture through the neck (appearing as a collar) is spondylolysis." }, { q: "How is spondylolisthesis graded?", opts: ["By pain level", "By percentage of vertebral body displacement (Meyerding classification)", "By number of fractures", "By age of patient"], correct: 1, rationale: "The Meyerding classification grades spondylolisthesis by the percentage of anterior displacement: Grade 1 (0-25%), Grade 2 (25-50%), Grade 3 (50-75%), Grade 4 (75-100%), Grade 5 (spondyloptosis >100%)." }] },
    { title: "CT Pulmonary Angiography for PE", clinicalHistory: "58-year-old female, 3 days post-hip replacement, presents with sudden onset chest pain and tachypnea. D-dimer elevated. Heart rate 120 bpm.", findings: [{ finding: "Intraluminal filling defect in right pulmonary artery", description: "Low-density clot visible within the contrast-enhanced pulmonary artery" }, { finding: "Right heart strain", description: "RV/LV ratio >1 suggesting right heart pressure overload" }, { finding: "Bilateral small effusions", description: "Small bilateral pleural effusions" }], diagnosis: "Acute pulmonary embolism with right heart strain", discussionPoints: [{ point: "CT technique", detail: "Bolus tracking with ROI in the pulmonary trunk. Scan during peak pulmonary artery enhancement" }, { point: "Contrast timing", detail: "Bolus tracking threshold ~100 HU in the pulmonary trunk. Scan delay is critical for PE detection" }, { point: "Patient preparation", detail: "Verify renal function (eGFR), pregnancy status, contrast allergy history. Ensure adequate IV access (18-20 gauge)" }], imageRefs: ["ctpa-pulmonary-embolism.jpg", "rv-strain-ct.jpg"], difficulty: "hard", questions: [{ q: "Where is the ROI placed for bolus tracking in CT pulmonary angiography?", opts: ["Ascending aorta", "Main pulmonary artery/trunk", "Left ventricle", "Superior vena cava"], correct: 1, rationale: "For CTPA, the ROI is placed in the main pulmonary artery/trunk. Scanning begins when the contrast reaches a threshold (typically 100 HU) in the pulmonary arteries for optimal opacification." }, { q: "What finding suggests right heart strain in PE?", opts: ["Left ventricular enlargement", "RV/LV diameter ratio >1", "Pericardial effusion", "Aortic dilation"], correct: 1, rationale: "An RV/LV ratio >1 indicates right ventricular dilation from acute pressure overload caused by the pulmonary embolism. This is a marker of severity and may influence treatment decisions." }] },
    { title: "Barium Swallow — Esophageal Stricture", clinicalHistory: "68-year-old male with progressive difficulty swallowing (dysphagia) over 6 months, initially with solids, now with liquids. Unintentional weight loss of 10 kg.", findings: [{ finding: "Irregular narrowing of the distal esophagus", description: "Abrupt shouldering with irregular mucosal pattern at the gastroesophageal junction" }, { finding: "Proximal esophageal dilation", description: "The esophagus proximal to the stricture is dilated due to obstruction" }, { finding: "Mucosal destruction", description: "Loss of normal mucosal fold pattern at the stricture site" }], diagnosis: "Suspected esophageal carcinoma at the GEJ", discussionPoints: [{ point: "Fluoroscopy technique", detail: "Single and double contrast views. RAO position projects esophagus between spine and heart for best visualization" }, { point: "Patient preparation", detail: "NPO 8 hours before. Both standing and prone views needed for complete evaluation" }, { point: "Radiation protection", detail: "Minimize fluoroscopy time, use pulsed fluoroscopy, last-image-hold, appropriate collimation" }], imageRefs: ["barium-swallow-stricture.jpg", "esophageal-narrowing.jpg"], difficulty: "hard", questions: [{ q: "Which position best demonstrates the esophagus during a barium swallow?", opts: ["Supine AP", "RAO (right anterior oblique)", "Left lateral", "PA"], correct: 1, rationale: "The RAO position projects the esophagus between the spine and the heart, providing optimal visualization without superimposition of these structures." }, { q: "What preparation is needed for a barium swallow?", opts: ["No preparation needed", "NPO 8 hours, remove dentures", "Full bowel prep", "Only clear liquids for 24 hours"], correct: 1, rationale: "Patients should be NPO for at least 8 hours before an upper GI/barium swallow. Dentures should be removed to prevent aspiration and artifact." }] },
    { title: "Neonatal Chest — Line and Tube Placement", clinicalHistory: "3-day-old neonate in the NICU. Portable AP chest radiograph ordered to verify placement of umbilical venous catheter (UVC) and endotracheal tube (ETT).", findings: [{ finding: "ETT tip position", description: "ETT tip 1.5 cm above the carina at the T2-T3 level" }, { finding: "UVC position", description: "UVC tip at the junction of the IVC and right atrium (at the diaphragm level)" }], diagnosis: "Acceptable ETT and UVC positions. Lungs clear bilaterally.", discussionPoints: [{ point: "Ideal ETT position", detail: "Tip at T1-T2 level in neonates, 1-2 cm above the carina. Too low → right mainstem intubation. Too high → accidental extubation" }, { point: "Pediatric technique", detail: "Use lowest mAs possible, tight collimation, short exposure time, immobilization (Pigg-O-Stat if needed)" }, { point: "ALARA in pediatrics", detail: "Children are more radiosensitive. Every repeat is amplified in risk. Get it right the first time" }], imageRefs: ["neonatal-chest-lines.jpg", "ett-position-neonatal.jpg"], difficulty: "medium", questions: [{ q: "Where should the ETT tip be positioned in a neonate?", opts: ["At the carina", "1-2 cm above the carina (T1-T2 level)", "In the right mainstem bronchus", "At the level of T7"], correct: 1, rationale: "The ETT tip should be positioned 1-2 cm above the carina (approximately T1-T2 level in neonates). Too low risks right mainstem intubation; too high risks accidental extubation." }, { q: "What immobilization device is commonly used for neonatal chest radiography?", opts: ["Sandbags only", "Pigg-O-Stat", "Velcro straps only", "No immobilization is needed"], correct: 1, rationale: "The Pigg-O-Stat is a plastic immobilization device that holds the infant upright for chest and abdominal radiographs, reducing motion and the need for repeat examinations." }] },
    { title: "Osteoarthritis Evaluation — Weight-Bearing Knees", clinicalHistory: "67-year-old female with bilateral knee pain worsening over 2 years, worse with weight-bearing activities. Morning stiffness lasting <30 minutes.", findings: [{ finding: "Medial joint space narrowing", description: "Asymmetric loss of the medial compartment joint space bilaterally, worse on the right" }, { finding: "Subchondral sclerosis", description: "Increased density of the subchondral bone in the medial compartments" }, { finding: "Osteophyte formation", description: "Marginal osteophytes at the medial femoral condyles and tibial plateaus" }], diagnosis: "Bilateral knee osteoarthritis, Grade 3 (Kellgren-Lawrence) right, Grade 2 left", discussionPoints: [{ point: "Weight-bearing views", detail: "PA weight-bearing with 10° caudad angle (Rosenberg view) best demonstrates early cartilage loss in the posterior condyles" }, { point: "Non-weight-bearing limitation", detail: "Supine/non-weight-bearing views may show normal joint spaces despite significant cartilage loss" }, { point: "Kellgren-Lawrence grading", detail: "Grade 0: Normal. Grade 1: Doubtful narrowing. Grade 2: Definite narrowing + osteophytes. Grade 3: Moderate narrowing. Grade 4: Bone-on-bone" }], imageRefs: ["oa-knees-weight-bearing.jpg", "osteophyte-formation.jpg"], difficulty: "medium", questions: [{ q: "Why are weight-bearing knee views important for OA assessment?", opts: ["They are faster to perform", "They demonstrate joint space narrowing under load, which may be hidden on supine views", "They require less radiation", "They show soft tissue better"], correct: 1, rationale: "Weight-bearing views compress the articular cartilage under physiologic load, demonstrating the true degree of joint space narrowing. Supine views may show falsely normal joint spaces." }, { q: "What radiographic features define osteoarthritis?", opts: ["Joint space widening and osteopenia", "Joint space narrowing, subchondral sclerosis, osteophytes, and subchondral cysts", "Periarticular erosions and osteopenia", "Uniform joint space narrowing"], correct: 1, rationale: "Classic OA radiographic features: non-uniform joint space narrowing, subchondral sclerosis, osteophyte formation, and subchondral cyst formation. Unlike RA, which shows uniform narrowing and erosions." }] },
    { title: "CT Head — Acute Stroke Protocol", clinicalHistory: "74-year-old male with sudden onset right-sided weakness and aphasia starting 2 hours ago. CT head ordered stat to rule out hemorrhage before thrombolytic therapy.", findings: [{ finding: "No intracranial hemorrhage", description: "No high-density (bright) areas indicating acute blood" }, { finding: "Loss of gray-white differentiation in left MCA territory", description: "Subtle loss of distinction between gray and white matter in the left insular cortex and basal ganglia" }, { finding: "Dense MCA sign", description: "Hyperdense left middle cerebral artery suggesting thrombus" }], diagnosis: "Early acute left MCA territory ischemic stroke", discussionPoints: [{ point: "CT technique", detail: "Non-contrast CT head is the first-line imaging for acute stroke to exclude hemorrhage before thrombolysis" }, { point: "Window settings", detail: "Brain windows (W:80, L:40) and stroke windows (W:40, L:40) for subtle early ischemic changes" }, { point: "Time is brain", detail: "Scan must be completed and interpreted rapidly. Door-to-CT time should be <25 minutes in stroke protocols" }], imageRefs: ["ct-head-early-stroke.jpg", "dense-mca-sign.jpg"], difficulty: "hard", questions: [{ q: "Why is non-contrast CT the first imaging study in acute stroke?", opts: ["It shows the clot location", "It rapidly excludes intracranial hemorrhage, which is a contraindication to thrombolysis", "It provides better resolution than MRI", "It shows the penumbra"], correct: 1, rationale: "Non-contrast CT rapidly and reliably detects acute intracranial hemorrhage (appears bright/hyperdense). Hemorrhage is an absolute contraindication to thrombolytic therapy. CT is faster and more accessible than MRI in the acute setting." }, { q: "What is the 'dense MCA sign'?", opts: ["Dilated MCA on angiography", "A hyperdense (bright) MCA on non-contrast CT suggesting intraluminal thrombus", "A calcified MCA", "Hemorrhagic transformation"], correct: 1, rationale: "The dense MCA sign is a hyperdense (bright) middle cerebral artery on non-contrast CT, caused by acute thrombus within the vessel. It is an early sign of MCA occlusion in ischemic stroke." }] },
  ];
}

// ─── 20 STRUCTURED LESSONS ───
export function generateCamrtLessons(): CamrtLesson[] {
  return [
    { title: "X-ray Production and the X-ray Tube", content: "## Learning Objectives\n- Describe the components of the x-ray tube\n- Explain bremsstrahlung and characteristic radiation production\n- Understand the line-focus principle and anode heel effect\n\n## Key Points\n- The x-ray tube consists of a cathode (filament + focusing cup) and anode (target + rotor)\n- Thermionic emission releases electrons from the heated filament\n- Only ~1% of kinetic energy is converted to x-rays; 99% becomes heat\n- Bremsstrahlung: continuous spectrum from electron deceleration near nuclei\n- Characteristic: discrete energies from inner-shell electron displacement\n- Tungsten K-shell binding energy: 69.5 keV (minimum kVp for characteristic radiation)\n- Line-focus principle: angled target creates smaller effective focal spot\n- Anode heel effect: cathode side has greater beam intensity\n\n## Exam Traps\n- Characteristic radiation requires minimum 69.5 kVp from tungsten target\n- The cathode side goes over the THICKEST body part (not thinnest)\n- Rotating anode distributes heat, not the cathode\n\n## Memory Aids\n- 'BREM-STOP' = BREMsstrahlung = electrons STOP near nucleus\n- 'CHAR-SHELL' = CHARacteristic = inner SHELL electron ejected\n- Cathode = Thickest (both start with hard consonant sounds)\n\n## Mini Quiz\n1. What percentage of kinetic energy becomes x-rays? (Answer: ~1%)\n2. What is the K-shell binding energy of tungsten? (Answer: 69.5 keV)\n3. Which type of radiation produces a continuous spectrum? (Answer: Bremsstrahlung)", category: "Physics", modality: "X-ray", keyConcepts: ["Thermionic emission", "Bremsstrahlung radiation", "Characteristic radiation", "Line-focus principle", "Anode heel effect"], formulas: [{ name: "Heat Units (single phase)", formula: "HU = kVp × mA × time × generator factor" }], difficulty: 2 },
    { title: "Exposure Factors: kVp, mAs, and Technique Selection", content: "## Learning Objectives\n- Understand the relationship between kVp, mAs, and image quality\n- Apply the 15% rule\n- Use the density maintenance formula for SID changes\n\n## Key Points\n- kVp controls beam quality (penetrating ability) and is the PRIMARY controlling factor for contrast\n- mAs controls beam quantity and is the PRIMARY controlling factor for density/receptor exposure\n- 15% rule: ↑kVp 15% ≈ doubling mAs for receptor exposure\n- Density maintenance formula: mAs₂ = mAs₁ × (SID₂/SID₁)²\n- Reciprocity law: any mA × time combination yielding same mAs = same exposure\n\n## Exam Traps\n- kVp controls CONTRAST (not density in the primary sense)\n- mAs controls DENSITY (not contrast)\n- Doubling mAs doubles density, but doubling kVp more than doubles it\n\n## Memory Aids\n- 'K for Kontrast' = kVp controls contrast\n- 'mAs = more Atoms hitting receptor = more density'\n- 15% Rule: 'Fifteen for Free' — 15% kVp increase = free doubling of exposure\n\n## Mini Quiz\n1. What is the primary controlling factor for contrast? (Answer: kVp)\n2. If SID increases from 100 to 180 cm, by what factor must mAs increase? (Answer: 3.24×)\n3. If you increase kVp by 15%, how should you adjust mAs? (Answer: Reduce by half)", category: "Physics", modality: "X-ray", keyConcepts: ["kVp-contrast relationship", "mAs-density relationship", "15% rule", "Density maintenance formula", "Reciprocity law"], formulas: [{ name: "15% Rule", formula: "↑kVp 15% ≈ 2× mAs" }, { name: "Density Maintenance", formula: "mAs₂ = mAs₁ × (SID₂/SID₁)²" }], difficulty: 2 },
    { title: "Digital Radiography: CR and DR Systems", content: "## Learning Objectives\n- Compare computed radiography (CR) and digital radiography (DR)\n- Understand exposure indicators and their significance\n- Recognize exposure creep and its implications\n\n## Key Points\n- CR: Photostimulable phosphor (PSP) plates in cassettes, read by laser scanner\n- DR Direct: Amorphous selenium (a-Se) converts x-rays directly to electrical signal\n- DR Indirect: Scintillator (CsI or Gd₂O₂S) converts x-rays to light, then TFT array converts to signal\n- Exposure indicators reflect radiation reaching the detector (NOT patient dose directly)\n- Digital systems have wide dynamic range but this enables exposure creep\n- Exposure creep: unnecessary dose increase because images still look acceptable\n- Window level = brightness/density; Window width = contrast\n\n## Exam Traps\n- CR is NOT DR — CR requires a separate reader; DR provides immediate display\n- Exposure indicator shows detector exposure, not patient dose\n- Wide dynamic range is an advantage AND a risk (exposure creep)\n\n## Memory Aids\n- CR = Cassette Required; DR = Display Ready\n- 'Level = Lightness' (window level controls brightness)\n- 'Width = Washed out or White-black' (window width controls contrast range)", category: "Physics", modality: "X-ray", keyConcepts: ["Computed radiography", "Direct digital radiography", "Indirect digital radiography", "Exposure indicators", "Exposure creep", "Window/level"], formulas: [], difficulty: 2 },
    { title: "Radiation Protection Principles and ALARA", content: "## Learning Objectives\n- Apply ALARA principles in clinical practice\n- Know Canadian dose limits (CNSC regulations)\n- Understand cardinal principles of radiation protection\n\n## Key Points\n- ALARA: As Low As Reasonably Achievable\n- Three cardinal principles: Time, Distance, Shielding\n- Inverse square law: I ∝ 1/D²\n- Canadian dose limits (CNSC):\n  - Occupational: 50 mSv/year, 100 mSv/5 years\n  - Public: 1 mSv/year\n  - Lens: 20 mSv/year (averaged over 5 years)\n  - Extremities: 500 mSv/year\n  - Pregnant worker fetus: 4 mSv for remainder of pregnancy\n- Personnel monitoring required when >1 mSv/year likely\n\n## Exam Traps\n- Canada's fetal dose limit is 4 mSv (not 5 mSv as in some US guidelines)\n- Lens dose limit recently reduced to 20 mSv/year (not the old 150 mSv)\n- The public limit is 1 mSv/year (not 5 mSv)\n\n## Memory Aids\n- 'TDS' = Time, Distance, Shielding\n- '50-100-1-4' = 50 annual, 100 cumulative, 1 public, 4 fetal\n- Inverse square: 'Double distance = Quarter dose'", category: "Radiation Protection", modality: "General", keyConcepts: ["ALARA", "Cardinal principles", "Inverse square law", "Canadian dose limits", "Personnel monitoring"], formulas: [{ name: "Inverse Square Law", formula: "I₁/I₂ = D₂²/D₁²" }], difficulty: 2 },
    { title: "Radiation Biology: Effects and Risks", content: "## Learning Objectives\n- Differentiate stochastic from deterministic effects\n- Understand the LNT model\n- Apply Bergonié and Tribondeau's law\n\n## Key Points\n- Stochastic effects: probabilistic, no threshold, severity not dose-related (cancer, genetic effects)\n- Deterministic effects: threshold-based, severity increases with dose (erythema, cataracts, ARS)\n- Linear non-threshold (LNT) model: any dose carries risk (conservative assumption)\n- Bergonié and Tribondeau: cells most radiosensitive when rapidly dividing, undifferentiated, long mitotic future\n- Most radiosensitive: lymphocytes, spermatogonia, erythroblasts, intestinal crypt cells\n- Least radiosensitive: nerve cells, muscle cells\n- LD 50/30: 3.5-4.5 Gy\n- Most sensitive pregnancy period: organogenesis (2-8 weeks)\n\n## Exam Traps\n- Cancer is stochastic (not deterministic)\n- Cataracts are deterministic (with threshold), NOT stochastic\n- LD 50/30 is about whole-body dose, not localized exposure", category: "Radiation Protection", modality: "General", keyConcepts: ["Stochastic effects", "Deterministic effects", "LNT model", "Bergonié and Tribondeau", "LD 50/30", "Radiosensitivity"], formulas: [], difficulty: 3 },
    { title: "Grids: Construction, Function, and Errors", content: "## Learning Objectives\n- Explain grid construction and grid ratio\n- Identify types of grid cutoff and their causes\n- Select appropriate grids for clinical situations\n\n## Key Points\n- Grid function: absorb scatter radiation to improve contrast\n- Grid ratio = h/D (height/interspace distance)\n- Higher ratio = better scatter cleanup but more technique needed\n- Grid conversion factors: 5:1≈2, 6:1≈3, 8:1≈4, 10:1≈5, 12:1≈5-6, 16:1≈6-7\n- Grid cutoff types:\n  1. Off-level: overall density loss\n  2. Off-center (lateral): unilateral density loss\n  3. Off-focus (wrong SID): bilateral density loss\n  4. Upside-down: center OK, severe bilateral cutoff\n\n## Exam Traps\n- Off-level = overall loss. Off-center = one side. Off-focus = both sides. Upside-down = severe both sides\n- Grid cutoff always requires a repeat — cannot be fixed by post-processing\n- Higher grid ratio = more technique = more patient dose", category: "Physics", modality: "X-ray", keyConcepts: ["Grid ratio", "Grid conversion factor", "Grid cutoff types", "Focused vs parallel grids", "Reciprocating grids"], formulas: [{ name: "Grid Ratio", formula: "r = h/D (height of lead strips / interspace distance)" }], difficulty: 2 },
    { title: "Chest Radiography Positioning and Evaluation", content: "## Learning Objectives\n- Position patients for PA and lateral chest projections\n- Evaluate chest radiographs for technical quality\n- Identify common positioning errors\n\n## Key Points\n- PA chest: 180 cm SID, T7 CR, full inspiration, scapulae out\n- Lateral chest: 180 cm SID, left side against receptor, arms raised\n- Proper inspiration: 10 posterior ribs or 7-8 anterior ribs\n- No rotation: spinous processes equidistant from medial clavicle ends\n- Proper exposure: thoracic spine faintly visible through heart\n- PA vs AP: PA minimizes cardiac magnification\n\n## Exam Traps\n- Heart size can ONLY be accurately assessed on PA (not AP)\n- Portable chest = AP projection = magnified heart\n- 10 POSTERIOR ribs = proper inspiration (not anterior)\n\n## Memory Aids\n- 'PA = Perfect Assessment' of heart size\n- '10 Post, 7 Ant' = inspiration criteria\n- 'Spin Equal Clav' = no rotation check", category: "Positioning", modality: "X-ray", keyConcepts: ["PA chest positioning", "Lateral chest positioning", "Inspiration criteria", "Rotation assessment", "Exposure evaluation"], formulas: [], difficulty: 1 },
    { title: "Upper Extremity Positioning: Hand to Shoulder", content: "## Learning Objectives\n- Position standard upper extremity projections\n- Know key centering points and tube angles\n- Identify positioning errors on images\n\n## Key Points\n- PA Hand: CR to 3rd MCP, fingers separated\n- Oblique Hand: 45° lateral rotation\n- PA Wrist: CR to midcarpal area, fingers flexed to flatten wrist\n- Scaphoid: PA with ulnar deviation (± 15-20° tube angle toward elbow)\n- Lateral Wrist: ulnar surface down, radius and ulna superimposed\n- AP Forearm: full extension, supination, include both joints\n- Lateral Elbow: 90° flexion, epicondyles superimposed, look for fat pad sign\n- Shoulder External Rotation: greater tuberosity in profile (palm forward)\n- Shoulder Internal Rotation: lesser tuberosity in profile (back of hand to thigh)\n\n## Exam Traps\n- Scaphoid: ULNAR deviation (not radial)\n- Fat pad sign on lateral elbow = effusion = occult fracture in trauma\n- Both joints MUST be included on forearm", category: "Positioning", modality: "X-ray", keyConcepts: ["Hand positioning", "Wrist positioning", "Scaphoid view", "Elbow positioning", "Shoulder rotations"], formulas: [], difficulty: 2 },
    { title: "Lower Extremity Positioning: Foot to Pelvis", content: "## Learning Objectives\n- Position standard lower extremity projections\n- Know key angulations and positioning criteria\n- Evaluate lower extremity radiographs\n\n## Key Points\n- AP Foot: 10° toward heel to open metatarsal joints\n- Ankle Mortise: 15-20° internal rotation of entire leg\n- AP Knee: 5-7° cephalad to open joint space\n- AP Pelvis: 15-20° internal rotation of legs to show femoral necks\n- Cross-table lateral hip: horizontal beam, trauma only, don't move affected leg\n- Frog-leg lateral hip: NON-trauma only, flexed and abducted 40-45°\n\n## Exam Traps\n- AP foot angle: toward HEEL (posterior), not toward toes\n- Mortise: rotate ENTIRE LEG, not just the foot\n- AP pelvis: internal rotation for femoral necks, but NEVER in trauma\n\n## Memory Aids\n- 'Foot: 10 to the heel'\n- 'Mortise: 15-20 in'\n- 'Knee: 5-7 up'\n- 'Cross = Crisis (trauma), Frog = Fun (elective)'", category: "Positioning", modality: "X-ray", keyConcepts: ["Foot angulation", "Ankle mortise rotation", "Knee angulation", "Pelvis rotation", "Hip projections"], formulas: [], difficulty: 2 },
    { title: "Spine Radiography: Cervical, Thoracic, and Lumbar", content: "## Learning Objectives\n- Position standard spine projections\n- Know key tube angles and landmarks\n- Evaluate spine radiographs\n\n## Key Points\n- AP Cervical: 15-20° cephalad to C4\n- Lateral Cervical: 180 cm SID, MUST show C1-T1\n- Open Mouth: dens visible between C1 lateral masses\n- AP Lumbar: CR perpendicular to L3 (iliac crest)\n- Lateral Lumbar: CR to L3, knees flexed, sponge under waist\n- Oblique Lumbar: 45° rotation, Scotty dog appearance\n- LPO = right zygapophyseal joints; RPO = left\n- Breathing technique for lateral T-spine: low mA, long exposure\n\n## Exam Traps\n- Must show ALL 7 cervical vertebrae (C1-C7 + C7-T1)\n- Scotty dog NECK = pars interarticularis (spondylolysis = collar/break)\n- LPO shows the DOWN SIDE joints (right)\n\n## Memory Aids\n- 'LPO → Right joints (down side)'\n- 'Scotty dog parts: Eye=Pedicle, Nose=TP, Ear=SAP, Leg=IAP, Neck=Pars'", category: "Positioning", modality: "X-ray", keyConcepts: ["Cervical spine positioning", "Lumbar spine positioning", "Scotty dog anatomy", "Open mouth view", "Breathing technique"], formulas: [], difficulty: 2 },
    { title: "Skull and Sinus Radiography", content: "## Learning Objectives\n- Position standard skull and sinus projections\n- Know key angles for Caldwell, Waters, and Towne\n- Understand the importance of erect positioning for sinuses\n\n## Key Points\n- Caldwell (PA axial): 15° caudad → petrous ridges in lower 1/3 of orbits → frontal/ethmoid sinuses\n- Waters (parietoacanthial): OML 37° to receptor → petrous below maxillary sinuses → maxillary sinuses\n- Towne (AP axial): 30° caudad → occipital bone, foramen magnum, dorsum sellae\n- Lateral Skull: true lateral confirmed by orbital roof superimposition\n- Sinuses MUST be erect with horizontal beam for air-fluid levels\n\n## Exam Traps\n- Waters: OML at 37° (not MML)\n- Sinuses: MUST be erect (supine = no fluid levels visible)\n- Caldwell: 15° caudad, not cephalad\n\n## Memory Aids\n- 'Caldwell = 15 Caudad'\n- 'Waters = 37 degrees (WATERs → think of water/fluid levels → must be erect!)'\n- 'Towne = 30 down (Caudad)'", category: "Positioning", modality: "X-ray", keyConcepts: ["Caldwell projection", "Waters projection", "Towne projection", "Lateral skull", "Erect sinus radiography"], formulas: [], difficulty: 2 },
    { title: "CT Principles and Image Quality", content: "## Learning Objectives\n- Understand Hounsfield units and CT numbers\n- Explain helical CT concepts including pitch\n- Optimize CT image quality parameters\n\n## Key Points\n- Hounsfield scale: Water=0, Air=-1000, Bone≈+1000\n- CT pitch = table travel per rotation / beam collimation\n- Thinner slices → better resolution but more noise\n- Iterative reconstruction → less noise than filtered back projection → allows dose reduction\n- Window settings: Brain (W:80, L:40), Lung (W:1500, L:-700), Bone (W:2000, L:300)\n- CTDI = dose per rotation; DLP = CTDIvol × scan length\n- Automatic tube current modulation (ATCM) adjusts mAs for patient size\n\n## Exam Traps\n- Pitch >1 = gaps/faster/lower dose; Pitch <1 = overlap/slower/higher dose\n- Thinner slices improve resolution but INCREASE noise (need more mAs)\n- CTDI is NOT total exam dose — DLP better represents total dose", category: "Physics", modality: "CT", keyConcepts: ["Hounsfield units", "CT pitch", "Slice thickness and noise", "Window settings", "CTDI and DLP", "Iterative reconstruction"], formulas: [{ name: "Pitch", formula: "Pitch = Table travel per rotation / Beam collimation" }, { name: "DLP", formula: "DLP = CTDIvol × scan length (cm)" }], difficulty: 3 },
    { title: "Contrast Media: Types, Reactions, and Management", content: "## Learning Objectives\n- Differentiate iodinated and barium contrast agents\n- Classify and manage contrast reactions\n- Know contraindications and preparation protocols\n\n## Key Points\n- Iodinated contrast: used for CT, angiography, urography\n- Barium sulfate: used for GI fluoroscopy (NOT if perforation suspected)\n- Water-soluble contrast (Gastrografin): used if perforation suspected\n- Non-ionic contrast: lower osmolality, fewer reactions, preferred\n- Reaction classification:\n  - Mild: hives, nausea, limited vomiting → observe, diphenhydramine\n  - Moderate: extensive hives, bronchospasm → epinephrine, bronchodilator\n  - Severe: anaphylaxis, cardiac arrest → epinephrine, CPR, code team\n- Always check: eGFR/creatinine, allergies, metformin use, pregnancy\n- Metformin: hold 48 hours AFTER contrast, check renal function before resuming\n\n## Exam Traps\n- Barium in peritoneum = peritonitis (never use if perforation suspected)\n- Metformin is held AFTER contrast (not before)\n- Non-ionic does NOT mean zero reactions — just fewer", category: "Patient Care", modality: "CT", keyConcepts: ["Iodinated contrast", "Barium sulfate", "Water-soluble contrast", "Reaction classification", "Metformin protocol", "Renal function screening"], formulas: [], difficulty: 2 },
    { title: "Patient Care: Infection Control in Medical Imaging", content: "## Learning Objectives\n- Apply standard and transmission-based precautions\n- Describe proper hand hygiene and PPE use\n- Manage contaminated equipment\n\n## Key Points\n- Standard precautions apply to ALL patients\n- Hand hygiene: before/after patient contact, before/after PPE\n- Transmission-based precautions:\n  - Contact (MRSA, C. diff): gown + gloves\n  - Droplet (influenza, COVID-19): surgical mask + eye protection\n  - Airborne (TB, measles, varicella): N95 respirator\n- PPE removal order: gloves → hand hygiene → gown → hand hygiene → eye protection → mask → hand hygiene\n- C. difficile: requires bleach (alcohol doesn't kill spores)\n- Equipment cleaning between patients is mandatory\n\n## Exam Traps\n- Standard precautions apply to ALL patients (not just those with known infections)\n- N95 for airborne, surgical mask for droplet (commonly confused)\n- C. diff requires BLEACH (alcohol-based sanitizers don't work)\n\n## Memory Aids\n- 'All means ALL' for standard precautions\n- 'TB = Top Barrier (N95)'\n- 'C. diff = Chlorine (bleach)'", category: "Patient Care", modality: "General", keyConcepts: ["Standard precautions", "Contact precautions", "Droplet precautions", "Airborne precautions", "Hand hygiene", "Equipment cleaning"], formulas: [], difficulty: 2 },
    { title: "Fluoroscopy: Principles and Dose Reduction", content: "## Learning Objectives\n- Understand fluoroscopy equipment and operation\n- Apply dose reduction strategies for fluoroscopy\n- Know regulatory dose limits for fluoroscopy\n\n## Key Points\n- Image intensifier: input phosphor (CsI) → photocathode → electron acceleration → output phosphor\n- Maximum fluoroscopic entrance exposure: 88 mGy/min (standard), 176 mGy/min (high-level)\n- Dose reduction strategies:\n  - Pulsed fluoroscopy (reduce pulse rate)\n  - Last-image-hold\n  - Tight collimation\n  - Image receptor close to patient\n  - Minimize magnification mode use\n- Magnification mode increases dose and improves resolution\n- Operator should stand on image receptor side (away from tube)\n\n## Exam Traps\n- Magnification mode INCREASES dose (not decreases)\n- 88 mGy/min is the standard limit (not 44 or 176)\n- Image receptor CLOSE to patient (not far away)", category: "Physics", modality: "Fluoroscopy", keyConcepts: ["Image intensifier", "Pulsed fluoroscopy", "Dose reduction strategies", "Magnification mode", "Operator positioning"], formulas: [], difficulty: 2 },
    { title: "Quality Control in Radiography", content: "## Learning Objectives\n- Describe routine QC tests and their frequency\n- Interpret QC test results\n- Understand acceptance criteria\n\n## Key Points\n- kVp accuracy: ±5% of set value\n- mAs reproducibility: coefficient of variation ≤5%\n- Beam alignment: perpendicular within ±1 degree\n- Collimation accuracy: ±2% of SID\n- AEC reproducibility: ±5%\n- Digital detector uniformity: checked monthly\n- Phantom testing: resolution, contrast, noise, uniformity\n- Lead apron inspection: annually by fluoroscopy\n\n## Exam Traps\n- kVp accuracy is ±5% (not ±10%)\n- Lead apron inspection is ANNUAL (not whenever)\n- AEC backup timer is a SAFETY device", category: "Quality Control", modality: "X-ray", keyConcepts: ["kVp accuracy", "mAs reproducibility", "Collimation testing", "AEC testing", "Phantom testing", "Lead apron inspection"], formulas: [], difficulty: 2 },
    { title: "Image Artifacts: Recognition and Correction", content: "## Learning Objectives\n- Identify common radiographic and CT artifacts\n- Determine the cause of each artifact\n- Apply appropriate correction strategies\n\n## Key Points\n- Motion: blurred structures → shorter exposure, immobilization\n- Grid cutoff: density loss patterns depend on type (off-level, off-center, off-focus, upside-down)\n- Quantum mottle: grainy appearance → increase mAs\n- Moiré pattern: zebra stripes from grid-detector interaction → reciprocating grid\n- Static: branching/lightning patterns → humidity control\n- CT beam hardening: dark bands between dense structures → correction algorithms\n- CT ring artifact: concentric rings → detector calibration\n- CT metal streak: radiating streaks from metal → MAR algorithms, increase kVp\n\n## Exam Traps\n- Each grid cutoff type has a DIFFERENT appearance pattern\n- Quantum mottle = too FEW photons (underexposure), not too many\n- Moiré occurs with STATIONARY grid + DR detector\n\n## Memory Aids\n- 'Off-LEVEL = OVERALL loss'\n- 'Off-CENTER = ONE side'\n- 'Off-FOCUS = BOTH sides'\n- 'UPSIDE-DOWN = CENTER ok, SIDES gone'", category: "Image Quality", modality: "X-ray", keyConcepts: ["Motion artifact", "Grid cutoff types", "Quantum mottle", "Moiré pattern", "CT artifacts", "Correction strategies"], formulas: [], difficulty: 2 },
    { title: "Abdominal and GI Radiography", content: "## Learning Objectives\n- Position standard abdominal radiograph views\n- Understand barium study preparation and technique\n- Evaluate abdominal radiographs\n\n## Key Points\n- KUB (AP abdomen): CR perpendicular at iliac crest, include diaphragm to symphysis pubis\n- Left lateral decubitus: left side down, horizontal beam → detect free air (rises to right, above liver)\n- Upright abdomen: detect air-fluid levels (bowel obstruction)\n- Barium swallow prep: NPO 8 hours, remove dentures\n- Barium enema prep: clear liquid diet, bowel prep, barium bag ~90 cm above table\n- RAO position: best for esophagus (between spine and heart)\n- Free air detection: left lat decub most sensitive. Allow 5-10 min for air to rise\n\n## Exam Traps\n- LEFT lateral decubitus for FREE AIR (air rises to RIGHT)\n- Barium is CONTRAINDICATED if perforation suspected (use Gastrografin)\n- Upright view shows air-FLUID LEVELS, decubitus shows FREE AIR", category: "Positioning", modality: "X-ray", keyConcepts: ["KUB positioning", "Left lateral decubitus", "Upright abdomen", "Barium swallow", "Free air detection"], formulas: [], difficulty: 2 },
    { title: "Pediatric Radiography Considerations", content: "## Learning Objectives\n- Apply ALARA principles specific to pediatric imaging\n- Select appropriate immobilization devices\n- Adapt technique for pediatric patients\n\n## Key Points\n- Children are MORE radiosensitive than adults (longer life for stochastic effects to manifest)\n- ALARA is PARAMOUNT: tight collimation, appropriate technique, minimize repeats\n- Immobilization: Pigg-O-Stat, sandbags, tape, compression bands, parental assistance (with lead)\n- Technique adaptation: lower kVp, lower mAs, shorter exposure times\n- Communication: age-appropriate, involve parents, distraction techniques\n- Gonadal shielding when possible (within ALARA considerations)\n- Scoliosis PA in adolescent females: reduces breast dose by ~96%\n\n## Exam Traps\n- Children are MORE radiosensitive (not equal to adults)\n- Pigg-O-Stat is for chest/abdomen immobilization in infants\n- PA (not AP) for scoliosis in females to reduce BREAST dose", category: "Patient Care", modality: "X-ray", keyConcepts: ["Pediatric radiosensitivity", "Immobilization devices", "Technique adaptation", "Communication strategies", "Breast dose reduction"], formulas: [], difficulty: 2 },
    { title: "Canadian Regulatory Framework for Medical Imaging", content: "## Learning Objectives\n- Understand the role of CNSC, CAMRT, and Health Canada\n- Know the regulatory framework for radiation protection in Canada\n- Apply professional ethics and standards\n\n## Key Points\n- CNSC (Canadian Nuclear Safety Commission): sets dose limits, licenses facilities\n- CAMRT (Canadian Association of Medical Radiation Technologists): professional body, certification\n- Health Canada: radiation protection regulations, safety codes\n- PIPEDA: privacy legislation governing health information\n- Provincial regulators: licensing, scope of practice (varies by province)\n- CAMRT Code of Ethics: patient welfare, competence, integrity, accountability\n- Incident reporting: all radiation incidents must be reported per facility policy\n- Continuing competence: mandatory for maintaining registration\n\n## Exam Traps\n- CNSC regulates dose limits for NUCLEAR ENERGY WORKERS (includes some RT positions)\n- PIPEDA is federal; provinces may have additional legislation (e.g., PHIPA in Ontario)\n- CAMRT certification ≠ provincial licensing (both may be required)\n\n## Memory Aids\n- 'CNSC = Canadian Nuclear Safety Commission = dose limits'\n- 'CAMRT = Certification And MRT standards'\n- 'PIPEDA = Privacy Information Protection'", category: "Professional Practice", modality: "General", keyConcepts: ["CNSC regulations", "CAMRT certification", "Health Canada", "PIPEDA", "Provincial licensing", "Code of Ethics"], formulas: [], difficulty: 2 },
  ];
}

